// Simplifies (X / C1) * C2 + (X % C1) to (X / C1) * (C2 - C1) + X.
// This is based on the identity: X = (X / C1) * C1 + (X % C1)
// So: (X / C1) * C2 + (X % C1) = (X / C1) * C2 + (X - (X / C1) * C1)
//                                 = (X / C1) * (C2 - C1) + X
// Requires C2 > C1. For OR, the low bits of (X / C1) * C2 must be zero.
static Value *foldDivRemRecompose(BinaryOperator &I, InstCombiner::BuilderTy &Builder) {
  Value *LHS = I.getOperand(0), *RHS = I.getOperand(1);
  bool IsOr = I.getOpcode() == Instruction::Or;
  Value *X;
  APInt RemC, MulC;
  bool IsSigned;

  // Match remainder on one side
  if (!MatchRem(LHS, X, RemC, IsSigned) && !MatchRem(RHS, X, RemC, IsSigned))
    return nullptr;

  // The other operand should be (X / RemC) * MulC
  Value *OtherOp = (LHS == MatchRem(LHS, X, RemC, IsSigned) ? LHS : RHS) ? 
                   (MatchRem(LHS, X, RemC, IsSigned) ? RHS : LHS) : nullptr;
  if (!OtherOp)
    return nullptr;

  // Match multiplication: OtherOp = MulOpV * MulC
  Value *MulOpV;
  if (!MatchMul(OtherOp, MulOpV, MulC))
    return nullptr;

  // MulOpV should be X / RemC (same divisor as remainder)
  Value *DivOpV;
  APInt DivC;
  bool DivIsSigned;
  if (MatchRem(MulOpV, DivOpV, DivC, DivIsSigned)) {
    // This handles the nested remainder case, not what we want
    return nullptr;
  }

  // Check for division: MulOpV = X / RemC
  if (!MatchDiv(MulOpV, DivOpV, DivC, IsSigned) || 
      DivOpV != X || DivC != RemC) {
    // Try shift as division by power of 2
    const APInt *ShAmt;
    if (!match(MulOpV, m_LShr(m_Specific(X), m_APInt(ShAmt))))
      return nullptr;
    DivC = APInt(RemC.getBitWidth(), 1);
    DivC <<= *ShAmt;
    if (DivC != RemC)
      return nullptr;
    // MulC was already computed by MatchMul from the shift
  }

  // We need C2 > C1 for the optimization to reduce the multiplier
  if (MulC <= RemC)
    return nullptr;

  // For OR, verify low bits of (X / C1) * C2 are zero (i.e., RemC <= low-zero bits of MulC)
  if (IsOr) {
    unsigned LowZeros = MulC.countTrailingZeros();
    // Remainder values are in range [0, RemC-1], so we need RemC-1 < 2^LowZeros
    // Equivalently: RemC <= 2^LowZeros
    APInt Threshold = APInt(RemC.getBitWidth(), 1);
    Threshold <<= LowZeros;
    if (RemC.ugt(Threshold))
      return nullptr;
  }

  // Create: (X / C1) * (C2 - C1) + X
  APInt NewMulC = MulC - RemC;
  Value *NewMul = Builder.CreateMul(MulOpV, ConstantInt::get(I.getType(), NewMulC),
                                    "reass.mul", /*NUW*/ true);
  return Builder.CreateAdd(NewMul, X);
}

CODEEOF"}

